  const MoviPremiumPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final localizer = MoviPremiumLocalizer.fromBuildContext(context);
    final pageState = ref.watch(moviPremiumPageStateProvider);
    final actionState = ref.watch(moviPremiumPageControllerProvider);
    final controller = ref.read(moviPremiumPageControllerProvider.notifier);

    return Scaffold(
      backgroundColor: theme.colorScheme.surface,
      body: SafeArea(
        child: SettingsContentWidth(
          child: RefreshIndicator(
            onRefresh: controller.refresh,
            child: ListView(
              padding: const EdgeInsets.fromLTRB(20, 16, 20, 32),
              children: [
                _PremiumHeader(
                  title: localizer.pageTitle,
                  subtitle: localizer.pageSubtitle,
                ),
                const SizedBox(height: 24),
                if (actionState.feedbackKind != null) ...[
                  _FeedbackCard(
                    message: localizer.feedback(actionState.feedbackKind!),
                    isError:
                        actionState.phase == MoviPremiumActionPhase.failure,
                    onDismiss: controller.clearFeedback,
                  ),
                  const SizedBox(height: 16),
                ],
                _PremiumHeroCard(
                  pageState: pageState,
                  localizer: localizer,
                  onSignIn: pageState.isAuthenticated
                      ? null
                      : () => context.push(AppRoutePaths.authOtp),
                ),
                const SizedBox(height: 16),
                _CurrentPlanCard(
                  title: localizer.currentPlanTitle,
                  value: pageState.hasActiveSubscription
                      ? localizer.activePlanLabel(pageState.activePlanId)
                      : localizer.currentPlanInactiveLabel,
                  badgeLabel: _statusBadgeLabel(localizer, pageState),
                ),
                const SizedBox(height: 16),
                if (pageState.shouldShowAccountHint) ...[
                  _InfoCard(
                    icon: Icons.person_outline,
                    message: localizer.accountRequiredHint,
                  ),
                  const SizedBox(height: 16),
                ],
                if (pageState.isBillingUnavailable) ...[
                  _InfoCard(
                    icon: Icons.info_outline,
                    message: localizer.billingUnavailableHint,
                  ),
                  const SizedBox(height: 16),
                ],
                if (pageState.isRestoreOnly) ...[
                  _InfoCard(
                    icon: Icons.restore,
                    message: localizer.restoreOnlyHint,
                  ),
                  const SizedBox(height: 16),
                ],
                _FeatureGroupCard(
                  title: localizer.cloudFeaturesTitle,
                  items: localizer.cloudFeatures,
                ),
                const SizedBox(height: 12),
                _FeatureGroupCard(
                  title: localizer.localFeaturesTitle,
                  items: localizer.localFeatures,
                ),
                const SizedBox(height: 12),
                _FeatureGroupCard(
                  title: localizer.discoveryFeaturesTitle,
                  items: localizer.discoveryFeatures,
                ),
                const SizedBox(height: 24),
                Text(
                  localizer.offersTitle,
                  style: theme.textTheme.titleLarge,
                ),
                const SizedBox(height: 12),
                if (pageState.isInitialLoading)
                  const Center(child: CircularProgressIndicator())
                else if (pageState.offers.isEmpty)
                  _EmptyOffersCard(
                    message: pageState.isBillingUnavailable
                        ? localizer.billingUnavailableHint
                        : localizer.retryButtonLabel,
                    actionLabel: localizer.retryButtonLabel,
                    onPressed: actionState.isBusy ? null : controller.refresh,
                  )
                else
                  ...pageState.offers.map(
                    (offer) => Padding(
                      padding: const EdgeInsets.only(bottom: 12),
                      child: _OfferCard(
                        offer: offer,
                        localizer: localizer,
                        highlighted: offer.id.toLowerCase().contains('annual'),
                        enabled: pageState.canPurchase &&
                            !pageState.hasActiveSubscription &&
                            !pageState.isRestoreOnly &&
                            !actionState.isBusy,
                        disabledMessage: _resolveOfferDisabledMessage(
                          localizer: localizer,
                          pageState: pageState,
                        ),
                        onPurchase: () => controller.purchase(offer.id),
                      ),
                    ),
                  ),
                const SizedBox(height: 12),
                _RestoreCard(
                  restoreLabel: localizer.restoreButtonLabel,
                  enabled: pageState.canRestore && !actionState.isBusy,
                  onRestore: controller.restore,
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }

  String _statusBadgeLabel(
    MoviPremiumLocalizer localizer,
    MoviPremiumPageState pageState,
  ) {
    if (pageState.hasActiveSubscription) {
      return localizer.currentPlanActiveLabel;
    }
    if (pageState.isRestoreOnly) {
      return localizer.restoreButtonLabel;
    }
    return localizer.currentPlanInactiveLabel;
  }

  String? _resolveOfferDisabledMessage({
    required MoviPremiumLocalizer localizer,
    required MoviPremiumPageState pageState,
  }) {
    if (!pageState.isAuthenticated) {
      return localizer.accountRequiredHint;
    }
    if (pageState.hasActiveSubscription) {
      return localizer.activeSubscriptionHint;
    }
    if (pageState.isBillingUnavailable) {
      return localizer.billingUnavailableHint;
    }
    if (pageState.isRestoreOnly) {
      return localizer.restoreOnlyHint;
    }
    return null;
  }
}

