      accountValue = 'Mode local';
      accountValueColor = Colors.white70;
    } else {
      accountValue = 'Cloud indisponible';
      accountValueColor = theme.colorScheme.error;
    }

    return _buildSettingsGroup([
      _buildSettingItem(
        title: 'Compte cloud',
        value: accountValue,
        valueColor: accountValueColor,
