          ],
          const SizedBox(height: 16),
          Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              SizedBox(
                width: 320,
                child: inProgressMovieAsync.when(
                  data: (inProgressMovieId) {
                    return MoviPrimaryButton(
