                      MoviFavoriteButton(isFavorite: true, onPressed: () {}),
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }
}

class _SagaMovieCard extends ConsumerWidget {
  const _SagaMovieCard({required this.media, required this.isAvailable});

  final MoviMedia media;
  final bool isAvailable;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    return Opacity(
      opacity: isAvailable ? 1.0 : 0.5,
      child: ColorFiltered(
        colorFilter: isAvailable
            ? const ColorFilter.mode(Colors.transparent, BlendMode.color)
            : const ColorFilter.matrix([
                0.2126,
                0.7152,
                0.0722,
                0,
                0,
                0.2126,
                0.7152,
                0.0722,
                0,
                0,
                0.2126,
                0.7152,
                0.0722,
                0,
                0,
                0,
                0,
                0,
                1,
                0,
              ]),
        child: MoviMediaCard(
          media: media,
          heroTag: 'saga_movie_${media.id}',
          onTap: isAvailable
              ? (mm) => navigateToMovieDetail(
                  context,
                  ref,
                  ContentRouteArgs.movie(mm.id),
                )
              : null,
        ),
      ),
    );
  }
}

import 'package:flutter_test/flutter_test.dart';

import 'package:movi/src/core/subscription/domain/failures/subscription_failure.dart';
import 'package:movi/src/features/settings/presentation/services/movi_premium_feedback_resolver.dart';

void main() {
  group('MoviPremiumFeedbackResolver', () {
    const resolver = MoviPremiumFeedbackResolver();

    test('maps billing unavailable errors explicitly', () {
      final feedback = resolver.resolveFailure(
        SubscriptionFailure.billingUnavailable(),
      );

      expect(feedback, MoviPremiumFeedbackKind.billingUnavailable);
    });

    test('maps cancelled purchases to a user-facing cancelled state', () {
      final feedback = resolver.resolveFailure(
        SubscriptionFailure.purchaseCancelled(),
      );

      expect(feedback, MoviPremiumFeedbackKind.purchaseCancelled);
    });

    test('maps timeout-like failures to network unavailable', () {
      final feedback = resolver.resolveFailure(
        SubscriptionFailure.storeTimeout('restore'),
      );

      expect(feedback, MoviPremiumFeedbackKind.networkUnavailable);
    });

    test('maps restore success without active plan to no purchase found', () {
      final feedback = resolver.resolveRestoreSuccess(
        hasActiveSubscription: false,
      );

      expect(feedback, MoviPremiumFeedbackKind.noPurchaseFound);
    });

    test('maps generic technical failures to technical failure', () {
      final feedback = resolver.resolveFailure(
        SubscriptionFailure.purchaseFailed('Unexpected store state.'),
      );

      expect(feedback, MoviPremiumFeedbackKind.technicalFailure);
    });
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';

import 'package:movi/src/core/auth/domain/entities/auth_models.dart';
import 'package:movi/src/core/auth/domain/repositories/auth_repository.dart';
import 'package:movi/src/core/auth/presentation/providers/auth_providers.dart';
import 'package:movi/src/core/subscription/domain/entities/billing_availability.dart';
import 'package:movi/src/core/subscription/domain/entities/subscription_offer.dart';
import 'package:movi/src/core/subscription/domain/entities/subscription_snapshot.dart';
import 'package:movi/src/core/subscription/domain/entities/subscription_status.dart';
import 'package:movi/src/core/subscription/presentation/providers/subscription_providers.dart';
import 'package:movi/src/features/settings/presentation/providers/movi_premium_providers.dart';

void main() {
  group('moviPremiumPageStateProvider', () {
    test('disables purchase and restore when account is missing', () {
      final container = ProviderContainer(
        overrides: [
          authRepositoryProvider.overrideWithValue(_FakeAuthRepository()),
          moviPremiumAuthProvider.overrideWith(
            (ref) => Stream<AuthSnapshot>.value(AuthSnapshot.unauthenticated),
          ),
          currentSubscriptionProvider.overrideWith(
            (ref) async => SubscriptionSnapshot(
              status: SubscriptionStatus.inactive,
              billingAvailability: BillingAvailability.available,
            ),
          ),
          subscriptionOffersProvider.overrideWith(
            (ref) async => const <SubscriptionOffer>[
              SubscriptionOffer(
                id: 'monthly',
                storeProductId: 'monthly',
                title: 'Monthly',
                description: 'Monthly premium access',
                displayPrice: '€4.99',
              ),
            ],
          ),
        ],
      );
      addTearDown(container.dispose);

      final state = container.read(moviPremiumPageStateProvider);

      expect(state.shouldShowAccountHint, isTrue);
      expect(state.canPurchase, isFalse);
      expect(state.canRestore, isFalse);
      expect(state.offers, isNotEmpty);
    });

    test('enables purchase and restore for authenticated users', () {
      const session = AuthSession(userId: 'user-1');

      final container = ProviderContainer(
        overrides: [
          authRepositoryProvider.overrideWithValue(
            _FakeAuthRepository(session: session),
          ),
          moviPremiumAuthProvider.overrideWith(
            (ref) => Stream<AuthSnapshot>.value(
              const AuthSnapshot(
                status: AuthStatus.authenticated,
                session: session,
              ),
            ),
          ),
          currentSubscriptionProvider.overrideWith(
            (ref) async => SubscriptionSnapshot(
              status: SubscriptionStatus.inactive,
              billingAvailability: BillingAvailability.available,
            ),
          ),
          subscriptionOffersProvider.overrideWith(
            (ref) async => const <SubscriptionOffer>[
              SubscriptionOffer(
                id: 'annual',
                storeProductId: 'annual',
                title: 'Annual',
                description: 'Annual premium access',
                displayPrice: '€39.99',
              ),
            ],
          ),
        ],
      );
      addTearDown(container.dispose);

      final state = container.read(moviPremiumPageStateProvider);

      expect(state.shouldShowAccountHint, isFalse);
      expect(state.canPurchase, isTrue);
      expect(state.canRestore, isTrue);
      expect(state.hasActiveSubscription, isFalse);
    });

    test('surfaces the active plan when subscription is already enabled', () {
      const session = AuthSession(userId: 'user-2');

      final container = ProviderContainer(
        overrides: [
          authRepositoryProvider.overrideWithValue(
            _FakeAuthRepository(session: session),
          ),
          moviPremiumAuthProvider.overrideWith(
            (ref) => Stream<AuthSnapshot>.value(
              const AuthSnapshot(
                status: AuthStatus.authenticated,
                session: session,
              ),
            ),
          ),
          currentSubscriptionProvider.overrideWith(
            (ref) async => SubscriptionSnapshot(
              status: SubscriptionStatus.active,
              billingAvailability: BillingAvailability.available,
              activePlanId: 'movi_premium_annual',
            ),
          ),
          subscriptionOffersProvider.overrideWith(
            (ref) async => const <SubscriptionOffer>[],
          ),
        ],
      );
      addTearDown(container.dispose);

      final state = container.read(moviPremiumPageStateProvider);

      expect(state.hasActiveSubscription, isTrue);
      expect(state.activePlanId, 'movi_premium_annual');
    });
  });
}

